def main(inputs, storages, files):
    # Where you drop the files you want summarized.
    # /storage/ is mounted (read-only) from ${HOST_STORAGE_ROOT}, which setup-dood.sh
    # creates at <repo-parent>/graph_mind/storage/. Drop files into
    # <repo-parent>/graph_mind/storage/inputs/ on the host — no workspace_id needed.
    # See local-file-summarizer.md for the full setup walkthrough.
    SCAN_DIR = '/storage/inputs'
    ALLOWED_EXTS = ('.txt', '.md', '.markdown', '.log', '.rst')

    if not files.exists(SCAN_DIR):
        return {
            'output': {
                'files': [],
                'total': 0,
                'error': f'{SCAN_DIR} does not exist. See local-file-summarizer.md \u2192 "File setup".',
            }
        }

    paths = []
    for name in sorted(files.list_dir(SCAN_DIR)):
        if name.startswith('.'):
            continue
        if name.endswith(ALLOWED_EXTS):
            paths.append(f'{SCAN_DIR}/{name}')

    return {'output': {'files': paths, 'total': len(paths)}}

