def main(inputs, storages):
    # Per-pass: take this file's chunk summaries from SUMMARIZE_CHUNK (an array, since
    # SUMMARIZE_CHUNK iterates), and append them to our own accumulator.
    chunk_summaries = (inputs.get('SUMMARIZE_CHUNK') or {}).get('output')
    if chunk_summaries is None:
        # Some runtimes pass the array directly under the node key.
        chunk_summaries = inputs.get('SUMMARIZE_CHUNK') or []
    if isinstance(chunk_summaries, str):
        chunk_summaries = [chunk_summaries]
    if not isinstance(chunk_summaries, list):
        chunk_summaries = [chunk_summaries]

    state = inputs.get('LOAD_NEXT') or {}
    file_path = state.get('file_path')

    # Loop self-state: append this file's summary to whatever we accumulated
    # on previous passes. inputs['ROLLUP'] is None on the first pass.
    prev_self = inputs.get('ROLLUP')
    accumulated = (prev_self or {}).get('output') or []
    if not isinstance(accumulated, list):
        accumulated = []

    if file_path:
        accumulated = list(accumulated) + [{
            'file_path': file_path,
            'chunk_summaries': chunk_summaries,
        }]

    return {'output': accumulated}
